mapper.select:
SELECT id, user_id, scope, category, title, keywords, content, priority, source_session_id, use_count, created_at, last_used_at
FROM core_memory
WHERE user_id = #{userId}
AND priority >= 3
AND (

        keywords LIKE CONCAT('%', #{kw}, '%')

)
ORDER BY priority DESC, last_used_at DESC
LIMIT #{limit}

SELECT id, user_id, scope, category, title, keywords, content, priority, source_session_id, use_count, created_at, last_used_at
FROM core_memory
WHERE user_id = #{userId}
ORDER BY priority DESC, last_used_at DESC
LIMIT #{limit}

mapper.update:
UPDATE core_memory
SET last_used_at = #{lastUsedAt},
    use_count = use_count + #{useCount}
WHERE id = #{id}

mapper.select:
SELECT id, user_id, scope, category, title, keywords, content, priority, source_session_id, use_count, created_at, last_used_at
FROM core_memory
WHERE user_id = #{userId}
AND priority  <=  #{maxPriority}
AND last_used_at  <  DATE_SUB(NOW(), INTERVAL #{minAgeDays} DAY)
ORDER BY priority ASC, last_used_at ASC
LIMIT #{limit}
